package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;
import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    private Constructor<CSVRecord> constructor;

    @BeforeEach
    public void setUp() throws NoSuchMethodException, SecurityException {
        constructor = CSVRecord.class.getDeclaredConstructor(String[].class, Map.class, String.class, long.class);
        constructor.setAccessible(true);
    }

    private CSVRecord createCSVRecord(String[] values, Map<String, Integer> mapping, String comment, long recordNumber) throws InstantiationException, IllegalAccessException, IllegalArgumentException, InvocationTargetException {
        return constructor.newInstance(values, mapping, comment, recordNumber);
    }

    @Test
    public void testSize_withNonEmptyValues() throws Exception {
        String[] values = new String[] {"value1", "value2", "value3"};
        Map<String, Integer> mapping = new HashMap<>();
        CSVRecord record = createCSVRecord(values, mapping, null, 1L);

        int size = record.size();

        assertEquals(3, size);
    }

    @Test
    public void testSize_withEmptyValues() throws Exception {
        String[] values = new String[0];
        Map<String, Integer> mapping = new HashMap<>();
        CSVRecord record = createCSVRecord(values, mapping, "comment", 2L);

        int size = record.size();

        assertEquals(0, size);
    }

    @Test
    public void testSize_withNullValuesArray() throws Exception {
        // This scenario is not expected as values is final and set in constructor, but test defensively
        String[] values = null;
        Map<String, Integer> mapping = new HashMap<>();
        CSVRecord record = createCSVRecord(values, mapping, null, 3L);

        int size = record.size();

        // size() will throw NullPointerException if values is null, so test for that
    }

}
